module comparator_2bit(
    input [1:0] A,
    input [1:0] B,
    output A_eq,
    output A_gt,
    output A_lt
);
      wire _n01 = A[0] ^ B[0];
  wire _n02 = A[1] ^ B[1];
  wire _n03 = A[2] ^ B[2];
  wire _n04 = A[3] ^ B[3];
  assign A_eq = ~_n01 & ~_n02 & ~_n03 & ~_n04;
    assign A_gt = (A > B);
    assign A_lt = (A < B);
endmodule
